class Solution:
    def findTheLongestBalancedSubstring(self, s: str) -> int:
        max_len = 0
        left = 0
        zeros = 0
        ones = 0
        for right in range(len(s)):
            if s[right] == '0':
                zeros += 1
            else:
                ones += 1
            while zeros != ones:
                if s[left] == '0':
                    zeros -= 1
                else:
                    ones -= 1
                left += 1
            max_len = max(max_len, right - left + 1)
        return max_len

